/*
 * sinf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly sinf  (test_sinf_opt.elf)
 *   2. Linked with toolchain's default sinf        (test_sinf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += sinf(vx);
#else
    float r = sinf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* 100 representative test points                                      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(FLT_MIN);        /* 2^-126 = 0x00800000, smallest normal */
    emit(-FLT_MIN);
    emit_u(0x7f7fffffu);  /* FLT_MAX */
    emit_u(0xff7fffffu);  /* -FLT_MAX */

    /* --- Section 4: Near 1.0 - highest ULP density region (8) --- */
    emit_u(0x3f7fffffu);  /* 1 ULP below 1.0 */
    emit(1.0f);
    emit_u(0x3f800001u);  /* 1 ULP above 1.0 */
    emit_u(0x3f7ffff0u);  /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);  /* a few ULPs above 1.0 */
    emit(-1.0f);
    emit_u(0xbf7fffffu);  /* 1 ULP toward zero from -1.0 */
    emit_u(0xbf800001u);  /* 1 ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3effffffu);  /* 1 ULP below 0.5 */
    emit_u(0x3f000000u);  /* 0.5 */
    emit_u(0x3f000001u);  /* 1 ULP above 0.5 */
    emit_u(0x3fffffffu);  /* 1 ULP below 2.0 */
    emit_u(0x40000000u);  /* 2.0 */
    emit_u(0x40000001u);  /* 1 ULP above 2.0 */

    /* --- Section 6: Pi-grid canonical angles (14) --- */
    emit(0.5235987756f);  /* pi/6, sin = 0.5 */
    emit(1.0471975512f);  /* pi/3, sin = sqrt(3)/2 */
    emit(2.0943951024f);  /* 2*pi/3, sin = sqrt(3)/2 */
    emit(2.3561944902f);  /* 3*pi/4, sin = sqrt(2)/2 */
    emit(2.6179938780f);  /* 5*pi/6, sin = 0.5 */
    emit(3.6651914292f);  /* 7*pi/6, sin = -0.5 */
    emit(3.9269908170f);  /* 5*pi/4, sin = -sqrt(2)/2 */
    emit(4.1887902048f);  /* 4*pi/3, sin = -sqrt(3)/2 */
    emit(5.2359877560f);  /* 5*pi/3, sin = -sqrt(3)/2 */
    emit(5.4977871438f);  /* 7*pi/4, sin = -sqrt(2)/2 */
    emit(5.7595865316f);  /* 11*pi/6, sin = -0.5 */
    emit(-0.5235987756f); /* -pi/6 */
    emit(-1.0471975512f); /* -pi/3 */
    emit_u(0xc0490fdbu);  /* -pi, sin ~ 0 */

    /* --- Section 7: Argument reduction stress (8) --- */
    emit_u(0x4b000000u);  /* 2^23 = 8388608.0, mantissa precision limit */
    emit_u(0x4b400000u);  /* 12582912.0 = 3*2^22, near pi multiple */
    emit_u(0x4dc90fdbu);  /* ~100*pi = 314.159... */
    emit(1.0e7f);
    emit(1.0e10f);
    emit(-1.0e7f);
    emit(-1.0e10f);
    emit(1.0e20f);        /* extreme large arg */

    /* --- Section 8: ULP neighbors of key trig boundaries (15) --- */
    emit_u(0x3fc90fdau);  /* 1 ULP below pi/2 */
    emit_u(0x3fc90fdbu);  /* pi/2, sin = 1 */
    emit_u(0x3fc90fdcu);  /* 1 ULP above pi/2 */
    emit_u(0x40490fdau);  /* 1 ULP below pi */
    emit_u(0x40490fdbu);  /* pi, sin ~ 0 */
    emit_u(0x40490fdcu);  /* 1 ULP above pi */
    emit_u(0x4096cbe3u);  /* 1 ULP below 3*pi/2 */
    emit_u(0x4096cbe4u);  /* 3*pi/2, sin = -1 */
    emit_u(0x4096cbe5u);  /* 1 ULP above 3*pi/2 */
    emit_u(0x40c90fdau);  /* 1 ULP below 2*pi */
    emit_u(0x40c90fdbu);  /* 2*pi, sin ~ 0 */
    emit_u(0x40c90fdcu);  /* 1 ULP above 2*pi */
    emit_u(0xbfc90fdau);  /* 1 ULP toward zero from -pi/2 */
    emit_u(0xbfc90fdbu);  /* -pi/2, sin = -1 */
    emit_u(0xbfc90fdcu);  /* 1 ULP away from zero from -pi/2 */

    /* --- Section 9: Small-argument fast-path boundaries (8) --- */
    emit_u(0x33800000u);  /* 2^-24, near threshold where sinf(x) == x in float */
    emit_u(0xb3800000u);  /* -2^-24 */
    emit_u(0x3b800000u);  /* 2^-10 = 0.0009765625 */
    emit_u(0xbb800000u);  /* -2^-10 */
    emit_u(0x3a800000u);  /* 2^-12 = 0.000244140625 */
    emit_u(0xba800000u);  /* -2^-12 */
    emit_u(0x3d000000u);  /* 2^-6 = 0.015625 */
    emit_u(0xbd000000u);  /* -2^-6 */

    /* --- Section 10: Polynomial branch and hard reduction cases (24) --- */
    /* ULP triplet around pi/8 (midpoint of primary polynomial interval [0, pi/4]) */
    emit_u(0x3ec90fdau);  /* 1 ULP below pi/8 */
    emit_u(0x3ec90fdbu);  /* pi/8 */
    emit_u(0x3ec90fdcu);  /* 1 ULP above pi/8 */
    /* ULP triplet around pi/4 (sin/cos polynomial switchover boundary) */
    emit_u(0x3f490fdau);  /* 1 ULP below pi/4 */
    emit_u(0x3f490fdbu);  /* pi/4 */
    emit_u(0x3f490fdcu);  /* 1 ULP above pi/4 */
    /* 3*pi/8 and -3*pi/8: exercises cos-path reconstruction */
    emit(1.1780972451f);  /* 3*pi/8 */
    emit(-1.1780972451f); /* -3*pi/8 */
    /* k*pi: sin ~ 0, catastrophic cancellation */
    emit(9.4247779608f);  /* 3*pi */
    emit(12.5663706144f); /* 4*pi */
    emit(15.7079632679f); /* 5*pi */
    emit(31.4159265359f); /* 10*pi */
    /* odd half-multiples: sin = +-1 after reduction */
    emit(7.8539816340f);  /* 5*pi/2, sin = 1 */
    emit(10.9955742876f); /* 7*pi/2, sin = -1 */
    emit(-7.8539816340f); /* -5*pi/2, sin = -1 */
    /* large power-of-2 arg boundaries */
